f_hat = np.fft.fftshift((np.fft.fft(f)))

# some sample parameters for VMD
alpha = 2000       # moderate bandwidth constraint
tau = 0.            # noise-tolerance (no strict fidelity enforcement) 允许有误差
K = 6              # 3 modes 模态个数
DC = 0             # no DC part imposed
init = 1           # initialize omegas uniformly
tol = 1e-7


# Run actual VMD code
# print(f, "ffff")
u, u_hat, omega = VMD(f, alpha, tau, K, DC, init, tol)

# u：二维数组，每一行对应一个时间序列（模态）
# u_hat：这些模态的频谱分布
# omega：估计出来的每个模态的中心频率
output = pd.DataFrame(u)
output.to_excel('2_分解/VMD/结果/vmd_result.xlsx')
# %%
# Simple Visualization of decomposed modes


plt.figure()
plt.plot(u.T)
plt.title('Decomposed modes')
#  分解模式


# For convenience here: Order omegas increasingly and reindex u/u_hat
sortIndex = np.argsort(omega[-1, :])
omega = omega[:, sortIndex]
u_hat = u_hat[:, sortIndex]
u = u[sortIndex, :]
linestyles = ['b', 'g', 'm', 'c', 'c', 'r', 'k']

fig1 = plt.figure()
plt.subplot(411)
plt.plot(t, f)
plt.xlim((0, 1))
# for key, value in fsub.items():
